head.b:skin:
/* ==========================================================================
   1. ELEMEN UMUM & UTILITAS
   ========================================================================== */

.stabilo {
    background-color: rgba(0, 0, 0, 1);
    padding: 2px 6px;
    border-radius: 4px;
}

a:hover {
    background-color: rgba(178, 34, 34, 1);
    color: #fff;
    font-style: bold;
    box-shadow: 0 0 10px 4px grey;
    border-radius: 2px;
    padding: 2px 8px;
}

a.img-link:hover {
    background-color: transparent;
    box-shadow: none;
    padding: 0;
}

a:hover:has(img) {
    background-color: transparent;
    box-shadow: none;
    padding: 0;
}

/* --- Perbaikan Utama Body & Animasi Background --- */
html, body {
    font-family: 'Fira Code', 'Fira Mono', monospace;
    margin: 0;
    line-height: 1.5;
    position: relative;
    overflow-x: hidden;
    color: #33FF33;
    background-color: #131314;
    background-image: 
        radial-gradient(circle at 20% 30%, rgba(26, 115, 232, 0.30) 0%, transparent 40%),
        radial-gradient(circle at 80% 70%, rgba(161, 68, 201, 0.30) 0%, transparent 45%),
        radial-gradient(circle at 50% 50%, rgba(217, 48, 37, 0.15) 0%, transparent 50%);
    background-size: 200% 200%;
    animation: geminiMesh 50s ease-in-out infinite;
}

/* Semua elemen teks otomatis mengikuti warna utama */
body h1, body h2, body h3, body h4, body h5, body h6, 
body a, body header, body nav a, body footer {
    color: #33FF33;
}


/* ==========================================================================
   2. TATA LETAK & STRUKTUR HALAMAN (LAYOUT)
   ========================================================================== */

header, nav, main, aside, footer {
    padding: 1rem;
    margin: 0 auto;
    max-width: 1200px;
    box-sizing: border-box;
}

header {
    background: rgba(20, 20, 20, 0.05);
    padding: 2rem 1rem;
    text-align: center; /* Membuat teks h1 dan p di dalam header berada di tengah */
}

nav {
    background: rgba(20, 20, 20, 0.05);
    margin-bottom: 1.5rem;
    padding: 1rem;
}

nav ul {
    list-style: none;
    padding: 0;
    margin: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 1.5rem;
    justify-content: center; /* Membuat daftar menu (ul) berada di tengah */
}

nav a {
    text-decoration: none;
    font-weight: bold;
}

main {
    display: flex;
    flex-direction: row;
    gap: 2rem;
    width: 100%;
}


/* ==========================================================================
   3. KOMPONEN KONTEN (POST, ASIDE, IMAGES)
   ========================================================================== */

.post, article {
    flex: 3;
    min-width: 0;
    background: rgba(40, 40, 40, 0.6);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    padding: 1.5rem;
    border-radius: 20px;
    border: 2px solid rgba(255, 16, 240, 1);
    box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.15);
    animation: glow-pulse 4s infinite ease-in-out;
}

aside {
    flex: 1;
    min-width: 0;
    background: rgba(40, 40, 40, 0.6);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    padding: 1.5rem;
    border-radius: 20px;
    border: 2px solid rgba(255, 16, 240, 1);
    box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.15);
    animation: glow-pulse 4s infinite ease-in-out;
}

img {
    max-width: 100%;
    height: auto;
    display: block;
    border-radius: 10px;
}

.center {
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
    text-align: center;
}

footer {
    background: rgba(20, 20, 20, 0.05);
    text-align: center;
    margin-top: 2rem;
    padding: 1.5rem;
}


/* ==========================================================================
   4. KEYFRAMES ANIMASI
   ========================================================================== */

@keyframes geminiMesh {
    0% {
        background-position: 0% 50%;
    }
    50% {
        background-position: 100% 100%;
    }
    100% {
        background-position: 0% 50%;
    }
}

@keyframes glow-pulse {
    0%, 100% {
        border-color: rgba(102, 255, 102, 0.25);
        box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.1),
                    0 0 5px rgba(102, 255, 102, 0.1);
    }
    50% {
        border-color: rgba(102, 255, 102, 0.8);
        box-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.15),
                    0 0 30px rgba(102, 255, 102, 0.5);
    }
}


/* ==========================================================================
   5. MEDIA QUERIES (DESAIN RESPONSIF)
   ========================================================================== */

@media (max-width: 600px) {
    main {
        flex-direction: column;
    }
    aside {
        margin-top: 1rem;
    }
}

b:includable.script:
    (function() {
      var items = 
    ;
      var msgs = 
    ;
      var config = 
    ;

// 

      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//

body.script:
particlesJS('particles-js', {
  particles: {
    number: { value: 40, density: { enable: true, value_area: 1200 } },
    color: { value: '#ffffff' },
    shape: { type: 'circle' },
    opacity: { value: 0.4, random: true },
    size: { value: 3, random: true },
    line_linked: { enable: true, distance: 150, color: '#ffffff', opacity: 0.3, width: 1 },
    move: { enable: true, speed: 3, direction: 'none', out_mode: 'out' }
  },
  interactivity: {
    detect_on: 'canvas',
    events: {
      onhover: { enable: true, mode: 'grab' },
      onclick: { enable: true, mode: 'push' }
    }
  },
  retina_detect: true
});
